setPane("sv-refined-request-submitted-follow-up", createSupportMacroContent("Request Submitted / Follow-Up", [{"label": "Use Case", "text": "Arabic customer-support macro for: Request Submitted / Follow-Up."}, {"label": "Answer", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nYour request has been forwarded to the relevant department for review. Please follow up with us after 24 hours to check the latest update.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nYour request has been forwarded to the relevant department for review. Please follow up with us after 24 hours to check the latest update.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "تم رفع الطلب والمتابعة", [{"label": "الإجابة", "text": "نعتذر جدا على هذه المشكلة\nبالفعل أنا أرسلت للقسم المختص في الوقت الحالى و ممكن تتواصل معانا بعد 24 ساعه حتى تعرف الرد الذي تم"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nنعتذر جدا على هذه المشكلة\nبالفعل أنا أرسلت للقسم المختص في الوقت الحالى و ممكن تتواصل معانا بعد 24 ساعه حتى تعرف الرد الذي تم\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
