setPane("sv-refined-recharge-through-visa", createSupportMacroContent("Recharge Through Visa", [{"label": "Use Case", "text": "Arabic customer-support macro for: Recharge Through Visa."}, {"label": "Answer", "text": "To recharge coins using Visa, please follow these steps:\n\n1- Go to your profile page.\n2- Open the Recharge section.\n3- Choose the coin package you want to recharge.\n4- Select Visa as the payment method and complete the transaction.\n\nIf you do not have a Visa card, please send your account ID so we can provide available recharge agents in your area."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nTo recharge coins using Visa, please follow these steps:\n\n1- Go to your profile page.\n2- Open the Recharge section.\n3- Choose the coin package you want to recharge.\n4- Select Visa as the payment method and complete the transaction.\n\nIf you do not have a Visa card, please send your account ID so we can provide available recharge agents in your area.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "الشحن عبر الفيزا", [{"label": "الإجابة", "text": "خطوات شحن الكوينز عن طريق الفيزا\n\n1- الدخول إلى الصفحة الرئيسية الخاصة بك.\n\n2- الدخول إلى خانة إعادة الشحن.\n\n3- إختيار كمية الكوينز المراد شحنها.\nإذا كنت لا تملك فيزا يرجى ارسال الآي دي الحساب لتقديم وكلاء الشحن في منطقتك للشحن عن طريقهم"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nخطوات شحن الكوينز عن طريق الفيزا\n\n1- الدخول إلى الصفحة الرئيسية الخاصة بك.\n\n2- الدخول إلى خانة إعادة الشحن.\n\n3- إختيار كمية الكوينز المراد شحنها.\nإذا كنت لا تملك فيزا يرجى ارسال الآي دي الحساب لتقديم وكلاء الشحن في منطقتك للشحن عن طريقهم\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-request-recharge-invoice", createSupportMacroContent("Request Recharge Invoice", [{"label": "Use Case", "text": "Arabic customer-support macro for: Request Recharge Invoice."}, {"label": "Answer", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nWe apologize for the recharge issue.\n\nPlease clarify when the recharge was made and send the recharge invoice showing the date, time, and transaction number.\n\nIf payment was made through a bank, please send the bank invoice. If it was made through a wallet, please send the invoice from the wallet app.\n\nThank you for contacting SUGO Customer Service."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nPlease clarify when the recharge was made and send the recharge invoice showing the date, time, and transaction number.\n\nIf payment was made through a bank, please send the bank invoice. If it was made through a wallet, please send the invoice from the wallet app.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب فاتورة شحن", [{"label": "الإجابة", "text": "مرحبا بك في خدمة عملاء سوجو,\n\nنعتذر عن المشكلة الحالية\nيرجى توضيح متى تم الشحن وارسال فاتورة الشحن تحتوي الوقت والتاريخ ورقم العملية (فاتورة بنكيه) ولو محفظه من خلال (برنامج المحفظه)\n\nشكرا لك ,\nخدمة عملاء سوجو"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nمرحبا بك في خدمة عملاء سوجو,\n\nنعتذر عن المشكلة الحالية\nيرجى توضيح متى تم الشحن وارسال فاتورة الشحن تحتوي الوقت والتاريخ ورقم العملية (فاتورة بنكيه) ولو محفظه من خلال (برنامج المحفظه)\n\nشكرا لك ,\nخدمة عملاء سوجو\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-add-remove-withdrawal-option", createSupportMacroContent("Add / Remove Withdrawal Option", [{"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nمرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nبرجاء تقديم الطلب من الرابط الاتي: https://micoworld.feishu.cn/share/base/form/shrcnm0SCrveAVtp0l5m25MBF8e\nبيتم المراجعه علي الطلب و الاضافه في خلال 24 الي 48 ساعه من تقديمه\nنشكرك على ثقتك في تواصلك معنا\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "إضافة أو إزالة خيار السحب", []));
setPane("sv-refined-cancel-withdrawal-request", createSupportMacroContent("Cancel Withdrawal Request", [{"label": "Use Case", "text": "Arabic customer-support macro for: Cancel Withdrawal Request."}, {"label": "Answer", "text": "To cancel a withdrawal request, please specify the transaction you want to cancel so we can assist you correctly.\n\nIf the request is submitted within the first 24 hours of the transaction, it will be sent to management for review, and the diamonds may be returned within one week depending on the review result.\n\nPlease note that a withdrawal cannot be canceled after 24 hours have passed from the transaction time."}, {"label": "Ticket", "text": "Welcome to Sugo,\n\nTo cancel a withdrawal request, please specify the transaction you want to cancel so we can assist you correctly.\n\nIf the request is submitted within the first 24 hours of the transaction, it will be sent to management for review, and the diamonds may be returned within one week depending on the review result.\n\nPlease note that a withdrawal cannot be canceled after 24 hours have passed from the transaction time.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب إلغاء السحب", [{"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nنعتذر جدا على المشكلة الصادرة لكن لا يمكن الغاء السحب بعد مرور 24 ساعة من العملية\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-fast-withdrawal-conditions", createSupportMacroContent("Fast Withdrawal Conditions", [{"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nFast Withdrawal Conditions:\n\nSupported Country: Egypt\n\nSupported Channels: Vodafone and Fawry\n\nWithdrawal Frequency: Once per day\n\nDaily Withdrawal Limit per User: ≤ 10 USD per time\n\nMonthly Total Withdrawal Limit: 300 USD/month\n\nAll small withdrawal amounts will be delivered for free within 6 hours.\n\nWithdrawal Requirements:\n\nYou must be a host in an agency.\n\nThe number of accounts registered on the same device must be 3 or fewer.\n\nThe account must not have been logged into on more than 3 devices.\n\nCharm level must be 3.\n\nUsers who are flagged as at risk or who do not meet the withdrawal requirements will not be able to perform small withdrawals.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "شروط السحب السريع", [{"label": "الإجابة", "text": "شروط السحب السريع :- بلد الدعم: مصر قناة الدعم: فودافون وفوري تكرار السحب: مرة واحدة في اليوم حد السحب اليومي لمستخدم واحد: <=10 دولار أمريكي/الوقت الحد الإجمالي للسحب: 300 دولار أمريكي/الشهر سيتم تسليم جميع المبالغ الصغيرة مجانًا خلال 6 ساعات.\n\nمتطلبات السحب: لازم تبقي مضيفة في وكالة, لازم عدد الحسابات المسجلة على نفس الجهاز يكون 3 او اقل والحساب نفسه لم يتم فتحه على اكثر من 3 اجهزة, مستوي الجاذبية 3 ولن يتمكن المستخدمون المعرضون للخطر أو الذين لا يستوفون متطلبات السحب من إجراء عمليات سحب بمبالغ صغيرة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nشروط السحب السريع :- بلد الدعم: مصر قناة الدعم: فودافون وفوري تكرار السحب: مرة واحدة في اليوم حد السحب اليومي لمستخدم واحد: <=10 دولار أمريكي/الوقت الحد الإجمالي للسحب: 300 دولار أمريكي/الشهر سيتم تسليم جميع المبالغ الصغيرة مجانًا خلال 6 ساعات.\n\nمتطلبات السحب: لازم تبقي مضيفة في وكالة, لازم عدد الحسابات المسجلة على نفس الجهاز يكون 3 او اقل والحساب نفسه لم يتم فتحه على اكثر من 3 اجهزة, مستوي الجاذبية 3 ولن يتمكن المستخدمون المعرضون للخطر أو الذين لا يستوفون متطلبات السحب من إجراء عمليات سحب بمبالغ صغيرة.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-request-withdrawal-screenshot", createSupportMacroContent("Request Withdrawal Screenshot", [{"label": "Use Case", "text": "Arabic customer-support macro for: Request Withdrawal Screenshot."}, {"label": "Answer", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nWe apologize for the delay.\n\nPlease send a clear screenshot of the withdrawal transaction you are asking about, so we can review it and assist you properly.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nWe apologize for the delay.\n\nPlease send a clear screenshot of the withdrawal transaction you are asking about, so we can review it and assist you properly.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب لقطة شاشة للسحب", [{"label": "الإجابة", "text": "نعتذر عن التأخير الرجاء إرسال لقطه شاشه من السحب الذى تم"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nنعتذر عن التأخير الرجاء إرسال لقطه شاشه من السحب الذى تم\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-withdrawal-successful-but-not-received", createSupportMacroContent("Withdrawal Successful but Not Received", [{"label": "Use Case", "text": "Arabic customer-support macro for: Withdrawal Successful but Not Received."}, {"label": "Answer", "text": "We apologize for the issue you are experiencing.\n\nPlease note that when the withdrawal status appears as successful, it means the transaction has been completed from the system side. Please check your wallet balance. If the amount has not been received, please send a screen recording showing your wallet transactions for the last 5 days so we can review the case."}, {"label": "Ticket", "text": "Welcome to Sugo,\n\nWe apologize for the issue you are experiencing.\n\nPlease note that when the withdrawal status appears as successful, it means the transaction has been completed from the system side. Please check your wallet balance. If the amount has not been received, please send a screen recording showing your wallet transactions for the last 5 days so we can review the case.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "السحب ناجح ولم يصل المبلغ", [{"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nنعتذر لك جدا على هذه المشكلة\nلكن نجاح السخب يعني وصوله ممكن حضرتك تعملي تفقد لرصيد المحفظة الخاص بك وفي حالة عدم وصول المبلغ\nيرجى ارسال القطة شاشة فيديو من آخر عمليات المحفظة في آخر 5 ايام\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-withdrawal-through-management", createSupportMacroContent("Withdrawal Through Management", [{"label": "Use Case", "text": "Arabic customer-support macro for: Withdrawal Through Management."}, {"label": "Answer", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nWithdrawal through online management is usually used for hosts from Syria, Lebanon, and Iraq, as these countries are affected by USD restrictions and may not be able to use Payoneer.\n\nPlease make sure all required withdrawal information is filled in correctly so we can proceed with the payment.\n\nThe salary is usually paid within 1 to 2 working weeks after submitting the withdrawal request.\n\nThe host may receive a voucher from the administration and use it to collect cash from the available money agent in their area.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nWithdrawal through online management is usually used for hosts from Syria, Lebanon, and Iraq, as these countries are affected by USD restrictions and may not be able to use Payoneer.\n\nPlease make sure all required withdrawal information is filled in correctly so we can proceed with the payment.\n\nThe salary is usually paid within 1 to 2 working weeks after submitting the withdrawal request.\n\nThe host may receive a voucher from the administration and use it to collect cash from the available money agent in their area.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "السحب من خلال الإدارة", [{"label": "الإجابة", "text": "السحب من خلال الإدارة عبر الإنترنت\n1- عادةً ما يتم استخدام طريقة السحب هذه للمذيعين من سوريا/لبنان/العراق، وهي دول خاضعة للعقوبات بالدولار الأمريكي، ولا يمكن أن يكون لديها حساب بايونير.\n2- يجب على المضيفه ملء جميع المعلومات المطلوبة بشكل صحيح، حتى نتمكن من المضي قدمًا في الدفع.\n3- سيتم دفع الراتب عادة خلال اسبوع إلى اسبوعين (عمل) بعد تقديم طلب السحب\n4- سيحصل المضيفه على قسيمة من الإدارة، ويمكنه استخدام القسيمة للحصول على النقود من وكيل الأموال لدينا الموجود في منطقة المضيفه\n5- سيتم إلغاء الوكالات المدرجة في القائمة البيضاء، والتي يمكنها استلام الماس من جميع المراسي غير المصرية"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nالسحب من خلال الإدارة عبر الإنترنت\n1- عادةً ما يتم استخدام طريقة السحب هذه للمذيعين من سوريا/لبنان/العراق، وهي دول خاضعة للعقوبات بالدولار الأمريكي، ولا يمكن أن يكون لديها حساب بايونير.\n2- يجب على المضيفه ملء جميع المعلومات المطلوبة بشكل صحيح، حتى نتمكن من المضي قدمًا في الدفع.\n3- سيتم دفع الراتب عادة خلال اسبوع إلى اسبوعين (عمل) بعد تقديم طلب السحب\n4- سيحصل المضيفه على قسيمة من الإدارة، ويمكنه استخدام القسيمة للحصول على النقود من وكيل الأموال لدينا الموجود في منطقة المضيفه\n5- سيتم إلغاء الوكالات المدرجة في القائمة البيضاء، والتي يمكنها استلام الماس من جميع المراسي غير المصرية\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-withdrawal-waiting-period", createSupportMacroContent("Withdrawal Waiting Period", [{"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nWe apologize for the delay.\n\nWithdrawals are processed within 7 to 14 working days, ma'am. Please kindly wait for the full duration. Kindly note that working days do not include Fridays, Saturdays, public holidays, or official occasions.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "مدة انتظار السحب", [{"label": "الإجابة", "text": "نعتذر عن التأخير\nالسحب يتم من 7-14 (يوم عمل) يا فندم يرجىكي انتظري المده كاملة مع العلم يا فندم ان : ايام العمل خارج يوم الجمعه والسبت و الاجازات و المناسبات الرسميه."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nنعتذر عن التأخير\nالسحب يتم من 7-14 (يوم عمل) يا فندم يرجىكي انتظري المده كاملة مع العلم يا فندم ان : ايام العمل خارج يوم الجمعه والسبت و الاجازات و المناسبات الرسميه.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-agency-admin-whatsapp-group-requirements", createSupportMacroContent("Agency Admin WhatsApp Group Requirements", [{"label": "Use Case", "text": "Arabic customer-support macro for: Agency Admin WhatsApp Group Requirements."}, {"label": "Answer", "text": "To create an administrative WhatsApp group with management, the agency must meet all the following requirements:\n\n1- The agency income must double for two consecutive months.\n2- The agency must achieve 40 million diamonds within 30 days.\n3- Ten new active hosts must be added during the same 30-day period.\n\nAfter achieving the requirements, the WhatsApp group with management will be created in the month following the month in which the target was achieved."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo create an administrative WhatsApp group with management, the agency must meet the following requirements:\n\n1. The agency income must double for two consecutive months.\n2. The agency must achieve 40 million diamonds within 30 days.\n3. Ten new active hosts must be added during the same 30-day period.\n\nAfter achieving these requirements, the WhatsApp group with management will be created in the following month.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "شروط إنشاء جروب إداري للوكالة على واتساب", [{"label": "الإجابة", "text": "لعمل جروب إداري (واتساب) بالشروط التالية :\n1- يجب ان يتضاعف دخل الوكالة شهرين متتالين\n2- يجب ان تحقق الوكالة 40 مليون ماسة خلال 30 يوم مع 10 مضيفات جديدات تم اضافتهم في نفس ال 30 يوم فعالين\nبعد تحقيق المتطلبات التالية يتم عمل جروب واتساب مع الإدارة في الشهر التالي من الشهر الذي تم فيه تحقيق التارجت"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nشكراً لتواصلك معنا، نحن في خدمتك دائماً\n\nلعمل جروب إداري (واتساب) بالشروط التالية :\n1- يجب ان يتضاعف دخل الوكالة شهرين متتالين\n2- يجب ان تحقق الوكالة 40 مليون ماسة خلال 30 يوم مع 10 مضيفات جديدات تم اضافتهم في نفس ال 30 يوم فعالين\nبعد تحقيق المتطلبات التالية يتم عمل جروب واتساب مع الإدارة في الشهر التالي من الشهر الذي تم فيه تحقيق التارجت\nشكراً لك على تواصلك، نحن دائماً في خدمتك\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-agency-transfer-request", createSupportMacroContent("Agency Transfer Request", [{"label": "Use Case", "text": "Arabic customer-support macro for: Agency Transfer Request."}, {"label": "Answer", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nIf you want to transfer from your current agency, there are two possible ways:\n\n1. The current agent agrees and submits the transfer request to the administration.\n\nOr:\n\n2. If you have been inactive for two months, you may send a transfer request to the new agent.\n\nPlease provide the following information:\n\n1. ID:\n2. Phone number linked to the account:\n3. Name and ID of the current agency:\n4. Name and ID of the agency you want to transfer to:\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nIf you want to transfer from your current agency, there are two possible ways:\n\n1. The current agent agrees and submits the transfer request to the administration.\n\nOr:\n\n2. If you have been inactive for two months, you may send a transfer request to the new agent.\n\nPlease provide the following information:\n\n1. ID:\n2. Phone number linked to the account:\n3. Name and ID of the current agency:\n4. Name and ID of the agency you want to transfer to:\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب نقل الوكالة", [{"label": "الإجابة", "text": "ان كنتي تريدي النقل من الوكالة ال حضرتك مسجله فيها هناك طريقتان للنقل: الطريقه الاولي هي موافقه الوكيل و ارسال اليه الطلب لكي يقدمه للاداره من خلاله\n\nايضاً في حين التوقف لمده شهرين, تستطيعي ارسال طلب نقل للوكيل الجديد ب الشكل التالي\n\nالآي دي:\n\nرقم الهاتف المربوط بالحساب:\n\nاسم و الآي دي الوكالة المسجل فيها حاليًا:\n\nاسم و الآي دي الوكالة المراد النقل لها:"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nان كنتي تريدي النقل من الوكالة ال حضرتك مسجله فيها هناك طريقتان للنقل: الطريقه الاولي هي موافقه الوكيل و ارسال اليه الطلب لكي يقدمه للاداره من خلاله\n\nايضاً في حين التوقف لمده شهرين, تستطيعي ارسال طلب نقل للوكيل الجديد ب الشكل التالي\n\nالآي دي:\n\nرقم الهاتف المربوط بالحساب:\n\nاسم و الآي دي الوكالة المسجل فيها حاليًا:\n\nاسم و الآي دي الوكالة المراد النقل لها:\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-apply-to-open-host-agency", createSupportMacroContent("Apply to Open Host Agency", [{"label": "Use Case", "text": "Arabic customer-support macro for: Apply to Open Host Agency."}, {"label": "Answer", "text": "To create a host agency inside the app, please make sure all the following requirements are fully met:\n\n1- The minimum requirement to open an agency is five new hosts.\n2- The host accounts must be new and used on new devices.\n3- The applicant must not currently be a host.\n4- The applicant must not currently be a sub-agency agent.\n5- Each host account must have been registered less than 14 days ago.\n\nIf all requirements are met, please send the following information in full:\n- Your account ID.\n- The IDs of the five hosts.\n- Your real full name.\n- An active WhatsApp number with the international country code.\n- Country.\n\nPlease note that if you are currently a host or a sub-agency agent, the request cannot be submitted. The relevant management team will contact you within 24 to 48 hours via WhatsApp to explain all details."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo create a host agency inside the app, please make sure all the following requirements are fully met:\n\n1- The minimum requirement to open an agency is five new hosts.\n2- The host accounts must be new and used on new devices.\n3- The applicant must not currently be a host.\n4- The applicant must not currently be a sub-agency agent.\n5- Each host account must have been registered less than 14 days ago.\n\nIf all requirements are met, please send the following information in full:\n- Your account ID.\n- The IDs of the five hosts.\n- Your real full name.\n- An active WhatsApp number with the international country code.\n- Country.\n\nPlease note that if you are currently a host or a sub-agency agent, the request cannot be submitted. The relevant management team will contact you within 24 to 48 hours via WhatsApp to explain all details.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طلب فتح وكالة مضيفات", [{"label": "الإجابة", "text": "حتى تقدر تفتح وكالة مضيفات في التطبيق يجب توفر الشروط دي:\n\nأقل عدد مضيفين لفتح الوكالة هو 5 مضيفة جدد بحسابات جديده وأجهزة جديده..\n\nإذا كانت كل الشروط متاحة ولتقديم طلبك للادارة\nمن فضلك أرسل البيانات التالية:\nالآي دي :\nالاسم :\nرقم واتساب بالكود الدولي :\nالدولة :\nهل لديك وكالة في برنامج آخر ؟\n\nيرجى العلم انه سيتم التواصل معاك في خلال 24 ل 48 ساعة عن طريق الادارة وشرح كامل التفاصيل كلها واتساب لحضرتك."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nحتى تقدر تفتح وكالة مضيفات في التطبيق يجب توفر الشروط دي:\n\nأقل عدد مضيفين لفتح الوكالة هو 5 مضيفة جدد بحسابات جديده وأجهزة جديده..\n\nإذا كانت كل الشروط متاحة ولتقديم طلبك للادارة\nمن فضلك أرسل البيانات التالية:\nالآي دي :\nالاسم :\nرقم واتساب بالكود الدولي :\nالدولة :\nهل لديك وكالة في برنامج آخر ؟\n\nيرجى العلم انه سيتم التواصل معاك في خلال 24 ل 48 ساعة عن طريق الادارة وشرح كامل التفاصيل كلها واتساب لحضرتك.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-change-agency-for-anchor", createSupportMacroContent("Change Agency for Anchor", [{"label": "Use Case", "text": "Arabic customer-support macro for: Change Agency for Anchor."}, {"label": "Answer", "text": "If you are requesting to transfer from one agency to another, please follow the conditions below:\n\n1- If the current agent approves:\nThe transfer will be completed directly by the current agent according to the approved procedures.\n\n2- If the current agent does not approve:\nThe monthly target must be stopped for two full months. After this period ends, a transfer request can be submitted to the new agent.\n\n3- If there is abuse from the agent:\nPlease record a clear video showing the abuse, the agent's ID, and your own account ID.\n\n4- If the agent does not respond:\nIf the agent does not respond on WhatsApp and inside the app for at least three consecutive days, please record both conversations in full, showing the agent's ID and your account ID, then send the full video to the new agent so the required action can be taken.\n\nPlease note that if the WhatsApp conversation is not available, the transfer request cannot be submitted. All requirements must be followed before the request can be reviewed."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nIf you are requesting to transfer from one agency to another, please follow the conditions below:\n\n1- If the current agent approves:\nThe transfer will be completed directly by the current agent according to the approved procedures.\n\n2- If the current agent does not approve:\nThe monthly target must be stopped for two full months. After this period ends, a transfer request can be submitted to the new agent.\n\n3- If there is abuse from the agent:\nPlease record a clear video showing the abuse, the agent's ID, and your own account ID.\n\n4- If the agent does not respond:\nIf the agent does not respond on WhatsApp and inside the app for at least three consecutive days, please record both conversations in full, showing the agent's ID and your account ID, then send the full video to the new agent so the required action can be taken.\n\nPlease note that if the WhatsApp conversation is not available, the transfer request cannot be submitted. All requirements must be followed before the request can be reviewed.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "نقل المضيفة من وكالة إلى أخرى", [{"label": "الإجابة", "text": "في حالة طلب النقل من الوكالة، يرجى العلم بضرورة استيفاء الشروط التالية كاملةً:\n1- موافقة الوكيل الحالي\nيتم النقل مباشرة من خلال الوكيل الحالي وفقًا للإجراءات المعتمدة.\n2- في حالة عدم موافقة الوكيل الحالي\nيلزم إيقاف التارجت الشهري لمدة 2 أشهر كاملة، وبعد انتهاء المدة يمكن تقديم طلب نقل إلى الوكيل الجديد.\n3- في حالة وجود إساءة من الوكيل\nيرجى تسجيل فيديو واضح يتضمن:\nالإساءة بشكل واضح\n\nالآي دي الخاص بالوكيل\n\nالآي دي الخاص بك\n4- في حالة عدم رد الوكيل\nإذا لم يتم الرد من قبل الوكيل عبر واتساب والتطبيق لمدة لا تقل عن 3 أيام متتالية:\nيرجى تصوير المحادثتين كاملتين\n\nمع إظهار الآي دي الخاص بالوكيل والآي دي الخاص بك\n\nثم إرسال الفيديو كاملًا للوكيل الجديد لاتخاذ الإجراء اللازم مع العلم انه في حالة عدم توافر محادثة واتساب لا يكمن تقديم الطلب\n\n⚠️ يرجى الالتزام بجميع الشروط المذكورة حتى يمكن النظر في طلب النقل.\nنشكركم على تفهمكم وتعاونكم."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nنعتذر جدا على المشكلة الصادرة\nفي حالة طلب النقل من الوكالة، يرجى العلم بضرورة استيفاء الشروط التالية كاملةً:\n1- موافقة الوكيل الحالي\nيتم النقل مباشرة من خلال الوكيل الحالي وفقًا للإجراءات المعتمدة.\n2- في حالة عدم موافقة الوكيل الحالي\nيلزم إيقاف التارجت الشهري لمدة 2 أشهر كاملة، وبعد انتهاء المدة يمكن تقديم طلب نقل إلى الوكيل الجديد.\n3- في حالة وجود إساءة من الوكيل\nيرجى تسجيل فيديو واضح يتضمن:\nالإساءة بشكل واضح\n\nالآي دي الخاص بالوكيل\n\nالآي دي الخاص بك\n4- في حالة عدم رد الوكيل\nإذا لم يتم الرد من قبل الوكيل عبر واتساب والتطبيق لمدة لا تقل عن 3 أيام متتالية:\nيرجى تصوير المحادثتين كاملتين\n\nمع إظهار الآي دي الخاص بالوكيل والآي دي الخاص بك\n\nثم إرسال الفيديو كاملًا للوكيل الجديد لاتخاذ الإجراء اللازم مع العلم انه في حالة عدم توافر محادثة واتساب لا يكمن تقديم الطلب\n\n⚠️ يرجى الالتزام بجميع الشروط المذكورة حتى يمكن النظر في طلب النقل.\nنشكركم على تفهمكم وتعاونكم.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-change-sub-agency-to-main-agency", createSupportMacroContent("Change Sub-Agency to Main Agency", [{"label": "Use Case", "text": "Arabic customer-support macro for: Change Sub-Agency to Main Agency."}, {"label": "Answer", "text": "To upgrade from a sub-agency to a main agency, the following requirements must be met:\n\n1- The agency must already be activated.\n2- At least five active hosts must be available within 30 days.\n3- The agency must achieve a monthly target of more than 80 million diamonds.\n4- Approval from the main agency agent is required if the difference between the sub-agency and the main agency is less than 4 stars.\n5- The sub-agent must send a notification to the main agent through the WhatsApp group."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo upgrade from a sub-agency to a main agency, the following requirements must be met:\n\n1- The agency must already be activated.\n2- At least five active hosts must be available within 30 days.\n3- The agency must achieve a monthly target of more than 80 million diamonds.\n4- Approval from the main agency agent is required if the difference between the sub-agency and the main agency is less than 4 stars.\n5- The sub-agent must send a notification to the main agent through the WhatsApp group.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "تحويل وكالة فرعية إلى وكالة أساسية", [{"label": "الإجابة", "text": "التحويل من وكالة فرعيه لوكالة اساسيه بالشروط التالية :\n1- أن تكون وكالة تم تفعيلها\n2- لازم 5 مضيفات على الأقل في خلال 30 يوم يكونو فعالين\n3- لازم الوكال تكون محققه تارج شهرى اكبر من 80 مليون\n4- شرط الموافقة من الوكيل الاساسي التابعة له الوكالة ( إذا كان الفرق بين الوكالة الفرعية والوكالة الاساسية اقل من 4 نجوم )\n( يقوم الوكيل الفرعي بارسال اشعار للوكيل الاساسي على جروب واتساب )"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nشكراً لتواصلك معنا، نحن في خدمتك دائماً\n\nحضرتك تقدر تفتح وكالة فرعيه تحت وكيل وكالة\n\nتبع وكيل فا حضرتك بتتواصل مع الوكيل و بتطلب منه وكالة فرعيه و هوا بيتخذ الأجراءات\n\nشكراً لك على تواصلك، نحن دائماً في خدمتك\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-create-host-agency", createSupportMacroContent("Create Host Agency", [{"label": "Use Case", "text": "Arabic customer-support macro for: Create Host Agency."}, {"label": "Answer", "text": "To create a host agency inside the app, please make sure all the following requirements are fully met:\n\n1- The minimum requirement to open an agency is five new hosts.\n2- The host accounts must be new and used on new devices.\n3- The applicant must not currently be a host.\n4- The applicant must not currently be a sub-agency agent.\n5- Each host account must have been registered less than 14 days ago.\n\nIf all requirements are met, please send the following information in full:\n- Your account ID.\n- The IDs of the five hosts.\n- Your real full name.\n- An active WhatsApp number with the international country code.\n- Country.\n\nPlease note that if you are currently a host or a sub-agency agent, the request cannot be submitted. The relevant management team will contact you within 24 to 48 hours via WhatsApp to explain all details."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo create a host agency inside the app, please make sure all the following requirements are fully met:\n\n1- The minimum requirement to open an agency is five new hosts.\n2- The host accounts must be new and used on new devices.\n3- The applicant must not currently be a host.\n4- The applicant must not currently be a sub-agency agent.\n5- Each host account must have been registered less than 14 days ago.\n\nIf all requirements are met, please send the following information in full:\n- Your account ID.\n- The IDs of the five hosts.\n- Your real full name.\n- An active WhatsApp number with the international country code.\n- Country.\n\nPlease note that if you are currently a host or a sub-agency agent, the request cannot be submitted. The relevant management team will contact you within 24 to 48 hours via WhatsApp to explain all details.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "إنشاء وكالة مضيفات", [{"label": "الإجابة", "text": "لإنشاء وكالة مضيفات داخل التطبيق، يرجى التأكد من استيفاء الشروط التالية بالكامل:\n1- الحد الأدنى لعدد المضيفات لفتح الوكالة هو 5 مضيفات جدد،\n✔️ بحسابات جديدة\n✔️ وعلى أجهزة جديدة\n2- يشترط أن لا تكوني مضيفة حاليًا.\n3- يشترط أن لا تكوني وكيلة لوكالة فرعية.\n4- يجب أن يكون تاريخ تسجيل حساب كل مضيفة أقل من 14 يومًا.\n\n✅ في حال استيفاء جميع الشروط أعلاه\nيرجى إرسال البيانات التالية كاملة:\nالآي دي الخاص بحسابك\nآي دي المضيفات (الخمسة)\nالاسم الحقيقي ثلاثي\nرقم واتساب مفعّل مع الكود الدولي\nالدولة\n⚠️ يرجى العلم أنه في حالة كونكِ مضيفة حاليًا أو وكيلة لوكالة فرعية، لن يتم تقديم الطلب.\n📌 كما نود الإفادة بأنه سيتم التواصل معك خلال 24 إلى 48 ساعة من قبل الإدارة المختصة عبر واتساب لشرح جميع التفاصيل كاملة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nلإنشاء وكالة مضيفات داخل التطبيق، يرجى التأكد من استيفاء الشروط التالية بالكامل:\n1- الحد الأدنى لعدد المضيفات لفتح الوكالة هو 5 مضيفات جدد،\n✔️ بحسابات جديدة\n✔️ وعلى أجهزة جديدة\n2- يشترط أن لا تكوني مضيفة حاليًا.\n3- يشترط أن لا تكوني وكيلة لوكالة فرعية.\n4- يجب أن يكون تاريخ تسجيل حساب كل مضيفة أقل من 14 يومًا.\n\n✅ في حال استيفاء جميع الشروط أعلاه\nيرجى إرسال البيانات التالية كاملة:\nالآي دي الخاص بحسابك\nآي دي المضيفات (الخمسة)\nالاسم الحقيقي ثلاثي\nرقم واتساب مفعّل مع الكود الدولي\nالدولة\n⚠️ يرجى العلم أنه في حالة كونكِ مضيفة حاليًا أو وكيلة لوكالة فرعية، لن يتم تقديم الطلب.\n📌 كما نود الإفادة بأنه سيتم التواصل معك خلال 24 إلى 48 ساعة من قبل الإدارة المختصة عبر واتساب لشرح جميع التفاصيل كاملة..\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-create-sub-agency", createSupportMacroContent("Create Sub-Agency", [{"label": "Use Case", "text": "Arabic customer-support macro for: Create Sub-Agency."}, {"label": "Answer", "text": "You can create a sub-agency under a main agency by contacting the main agency agent directly and requesting a sub-agency. The agent will take the required steps according to the approved process.\n\nTo create an administrative WhatsApp group, the following requirements must be met:\n1- The agency income must double for two consecutive months.\n2- The agency must achieve 40 million diamonds within 30 days.\n3- Ten new active hosts must be added during the same 30-day period.\n\nAfter the requirements are achieved, a WhatsApp group with management will be created in the month following the month in which the target was achieved."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nYou can create a sub-agency under a main agency by contacting the main agency agent directly and requesting a sub-agency. The agent will take the required steps according to the approved process.\n\nTo create an administrative WhatsApp group, the following requirements must be met:\n1- The agency income must double for two consecutive months.\n2- The agency must achieve 40 million diamonds within 30 days.\n3- Ten new active hosts must be added during the same 30-day period.\n\nAfter the requirements are achieved, a WhatsApp group with management will be created in the month following the month in which the target was achieved.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "إنشاء وكالة فرعية", [{"label": "الإجابة", "text": "حضرتك تقدر تفتح وكالة فرعيه تحت وكيل وكالة\n\nتبع وكيل فا حضرتك بتتواصل مع الوكيل و بتطلب منه وكالة فرعيه و هوا بيتخذ الأجراءات"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nشكراً لتواصلك معنا، نحن في خدمتك دائماً\n\nحضرتك تقدر تفتح وكالة فرعيه تحت وكيل وكالة\n\nتبع وكيل فا حضرتك بتتواصل مع الوكيل و بتطلب منه وكالة فرعيه و هوا بيتخذ الأجراءات\n\nشكراً لك على تواصلك، نحن دائماً في خدمتك\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-add-game-request", createSupportMacroContent("Add Game Request", [{"label": "Use Case", "text": "Arabic customer-support macro for: Add Game Request."}, {"label": "Answer", "text": "The request to add games has been sent to the relevant department, and the games will be added to your account as soon as possible."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nThe request to add games has been sent to the relevant department, and the games will be added to your account as soon as possible.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طلب إضافة لعبة", [{"label": "الإجابة", "text": "تم إرسال طلب للقسم المختص بإضافة اللعب وسيتم إضافتها لحضرتك في أقرب وقت ممكن يا فندم إن شاء الله."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nتم إرسال طلب للقسم المختص بإضافة اللعب وسيتم إضافتها لحضرتك في أقرب وقت ممكن يا فندم إن شاء الله.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-add-games-request", createSupportMacroContent("Add Games Request", [{"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nWelcome! We are here to serve you.\n\nA request has been submitted to add the games, and it will be resolved as soon as possible.\n\nWe appreciate your communication with us and look forward to serving you in the best way possible.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طلب إضافة الألعاب", [{"label": "الإجابة", "text": "اهلا و سهلا ! نحن هنا لخدمتك\nتم تقديم طلب لأضافه الألعاب و سيتم حلها في أسرع وقت\n\nشكرا لتواصلك معنا"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nاهلا و سهلا ! نحن هنا لخدمتك\nتم تقديم طلب لأضافه الألعاب و سيتم حلها في أسرع وقت\n\nشكرا لتواصلك معنا\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-daily-and-family-tasks", createSupportMacroContent("Daily and Family Tasks", [{"label": "Use Case", "text": "Arabic customer-support macro for: Daily and Family Tasks."}, {"label": "Answer", "text": "There are current requirements for enabling daily and family tasks:\n\n1- Pass photo/frame verification and gender verification.\n2- Have a recharge record within the last 30 days.\n3- Account level must be 4 or above.\n4- Charm level must be 5 or above.\n\nThe feature will be activated once the required conditions are met, and it may appear on the next day after the activation requirements are completed."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nThere are current requirements for enabling daily and family tasks:\n\n1- Pass photo/frame verification and gender verification.\n2- Have a recharge record within the last 30 days.\n3- Account level must be 4 or above.\n4- Charm level must be 5 or above.\n\nThe feature will be activated once the required conditions are met, and it may appear on the next day after the activation requirements are completed.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "شروط المهام اليومية والعائلية", [{"label": "الإجابة", "text": "هناك شروط للمهام اليومية والعائلية الآن:\n1- اجتياز التحقق من الإطار والتحقق من الجنس\n2- وجود سجل شحن خلال آخر 30 يومًا\n3- يجب أن يكون مستوى الحساب 4 أو أكثر\n4- يجب أن يكون مستوى الجاذبية 5 أو أكثر ستكون الوظيفة نشطة إذا كانت القنوات تلبي متطلبات الشرط رقم 2 ستكون الوظيفة نشطة في اليوم التالي إذا كانت القنوات تلبي متطلبات الشروط 1 و3 و4"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nنعتذر جدا على اي ازعاج\nهناك شروط للمهام اليومية والعائلية الآن:\n1- اجتياز التحقق من الإطار والتحقق من الجنس\n2- وجود سجل شحن خلال آخر 30 يومًا\n3- يجب أن يكون مستوى الحساب 4 أو أكثر\n4- يجب أن يكون مستوى الجاذبية 5 أو أكثر ستكون الوظيفة نشطة إذا كانت القنوات تلبي متطلبات الشرط رقم 2 ستكون الوظيفة نشطة في اليوم التالي إذا كانت القنوات تلبي متطلبات الشروط 1 و3 و4\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-game-access-information", createSupportMacroContent("Game Access Information", [{"label": "Use Case", "text": "Arabic customer-support macro for: Game Access Information."}, {"label": "Answer", "text": "The game database has been updated, and games are now available according to the following requirements:\n\nFor Android users:\n- If the account belongs to a host, Charm level must be 3 or above.\n- If the account belongs to a supporter, VIP level must be 4 or above.\n\nFor iPhone users:\n- If the account belongs to a host, Charm level must be 2 or above.\n- If the account belongs to a supporter, VIP level must be 3 or above.\n\nGame access may also be enabled based on spending:\n- If the user spent more than 4,000 coins during last week or this week in other areas such as voice rooms, game access will be available for this week.\n- If the user spent more than 40,000 coins in other areas such as voice rooms, game access will be available permanently."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nThe game database has been updated, and games are now available according to the following requirements:\n\nFor Android users:\n- If the account belongs to a host, Charm level must be 3 or above.\n- If the account belongs to a supporter, VIP level must be 4 or above.\n\nFor iPhone users:\n- If the account belongs to a host, Charm level must be 2 or above.\n- If the account belongs to a supporter, VIP level must be 3 or above.\n\nGame access may also be enabled based on spending:\n- If the user spent more than 4,000 coins during last week or this week in other areas such as voice rooms, game access will be available for this week.\n- If the user spent more than 40,000 coins in other areas such as voice rooms, game access will be available permanently.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "معلومات الوصول إلى الألعاب", [{"label": "الإجابة", "text": "تم تحديث قاعدة البيانات بخصوص جميع الألعاب بقيت متاحه فقط بس في بعض الشروط للاندرويد : إذا كنت مضيفه بيكون لازم مستوي الجاذبية 3 او إذا كنت داعم بيكون لازم حسابك vip4\n\nإذا أنفق المستخدم أكثر من 4000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك) الأسبوع الماضي أو هذا الأسبوع، فسيكون لديه حق الوصول إلى الألعاب هذا الأسبوع.\n\nإذا أنفق المستخدم أكثر من 40000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك)، فسيكون لديه حق الوصول إلى الألعاب بشكل دائم.\n\nأما لمستخدمي ايفون : لو مضيفة بيكون مستوى الجاذبية 2 ولو داعم لازم يكون حسابك Vip3"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nتم تحديث قاعدة البيانات بخصوص جميع الألعاب بقيت متاحه فقط بس في بعض الشروط للاندرويد : إذا كنت مضيفه بيكون لازم مستوي الجاذبية 3 او إذا كنت داعم بيكون لازم حسابك vip4\n\nإذا أنفقت أكثر من 4000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك) الأسبوع الماضي أو هذا الأسبوع، فسيكون لديك حق الوصول إلى الألعاب هذا الأسبوع.\n\nإذا أنفقت أكثر من 40000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك)، فسيكون لديك حق الوصول إلى الألعاب بشكل دائم.\n\nأما لمستخدمي ايفون : لو مضيفة بيكون مستوى الجاذبية 2 ولو داعم لازم يكون حسابك Vip3\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-game-access-information-alternative", createSupportMacroContent("Game Access Information - Alternative", [{"label": "Use Case", "text": "Arabic customer-support macro for: Game Access Information - Alternative."}, {"label": "Answer", "text": "The game database has been updated, and games are now available according to the following requirements:\n\nFor Android users:\n- If the account belongs to a host, Charm level must be 3 or above.\n- If the account belongs to a supporter, VIP level must be 4 or above.\n\nFor iPhone users:\n- If the account belongs to a host, Charm level must be 2 or above.\n- If the account belongs to a supporter, VIP level must be 3 or above.\n\nGame access may also be enabled based on spending:\n- If the user spent more than 4,000 coins during last week or this week in other areas such as voice rooms, game access will be available for this week.\n- If the user spent more than 40,000 coins in other areas such as voice rooms, game access will be available permanently."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nThe game database has been updated, and games are now available according to the following requirements:\n\nFor Android users:\n- If the account belongs to a host, Charm level must be 3 or above.\n- If the account belongs to a supporter, VIP level must be 4 or above.\n\nFor iPhone users:\n- If the account belongs to a host, Charm level must be 2 or above.\n- If the account belongs to a supporter, VIP level must be 3 or above.\n\nGame access may also be enabled based on spending:\n- If the user spent more than 4,000 coins during last week or this week in other areas such as voice rooms, game access will be available for this week.\n- If the user spent more than 40,000 coins in other areas such as voice rooms, game access will be available permanently.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "معلومات الوصول إلى الألعاب - نسخة إضافية", [{"label": "الإجابة", "text": "بالتأكيد نتمنى لحضرتك حظ أوفر و لكن حابين نوضح لحضرتك\nالألعاب كلها سيستم ومكسب وخسارة يعني حظ للأسف منقدرش نتدخل أبدًا فيها يا فندم"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nبالتأكيد نتمنى لحضرتك حظ أوفر و لكن حابين نوضح لحضرتك\nالألعاب كلها سيستم ومكسب وخسارة يعني حظ للأسف منقدرش نتدخل أبدًا فيها يا فندم\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-games-access-conditions", createSupportMacroContent("Games Access Conditions", [{"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nThe database has been updated regarding all games — they are now available, but there are some conditions:\nFor Android users:\nIf you are a host, your charm level must be 3.\n\nIf you are a supporter, your account must be VIP4.\n\nIf you spent more than 1,000 coins (in other areas like the voice room, etc.) last week or this week, you will have access to the games for this week.\nIf you spent more than 10,000 coins (in other areas like the voice room, etc.), you will have permanent access to the games.\nFor iPhone users:\nIf you are a host, your charm level must be 2.\n\nIf you are a supporter, your account must be VIP3.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "شروط ظهور الألعاب", [{"label": "الإجابة", "text": "تم تحديث قاعدة البيانات بخصوص جميع الألعاب بقيت متاحه فقط بس في بعض الشروط للاندرويد : إذا كنت مضيفه بيكون لازم مستوي الجاذبية 3 او إذا كنت داعم بيكون لازم حسابك vip4\n\nإذا أنفقت أكثر من 4000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك) الأسبوع الماضي أو هذا الأسبوع، فسيكون لديك حق الوصول إلى الألعاب هذا الأسبوع.\n\nإذا أنفقت أكثر من 40000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك)، فسيكون لديك حق الوصول إلى الألعاب بشكل دائم.\n\nأما لمستخدمي ايفون : لو مضيفة بيكون مستوى الجاذبية 2 ولو داعم لازم يكون حسابك Vip3"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nتم تحديث قاعدة البيانات بخصوص جميع الألعاب بقيت متاحه فقط بس في بعض الشروط للاندرويد : إذا كنت مضيفه بيكون لازم مستوي الجاذبية 3 او إذا كنت داعم بيكون لازم حسابك vip4\n\nإذا أنفقت أكثر من 4000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك) الأسبوع الماضي أو هذا الأسبوع، فسيكون لديك حق الوصول إلى الألعاب هذا الأسبوع.\n\nإذا أنفقت أكثر من 40000 عملة (في مجالات آخرى مثل غرفة الصوت وما إلى ذلك)، فسيكون لديك حق الوصول إلى الألعاب بشكل دائم.\n\nأما لمستخدمي ايفون : لو مضيفة بيكون مستوى الجاذبية 2 ولو داعم لازم يكون حسابك Vip3\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-matching-issue-1", createSupportMacroContent("Matching Issue 1", [{"label": "Use Case", "text": "Arabic customer-support macro for: Matching Issue 1."}, {"label": "Answer", "text": "To receive matching messages, the following requirements must be met:\n\n1- Pass photo/frame verification and gender verification.\n2- Have more than 80 Chat Growth points.\n\nYou can check your Chat Growth points from your profile page, then Chat Growth, where the current number of points will be displayed."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nTo receive matching messages, the following requirements must be met:\n\n1- Pass photo/frame verification and gender verification.\n2- Have more than 80 Chat Growth points.\n\nYou can check your Chat Growth points from your profile page, then Chat Growth, where the current number of points will be displayed.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "مشكلة تطابق 1", [{"label": "الإجابة", "text": "للحصول على رسائل التطابق\n1- اجتياز التحقق من الإطار والتحقق من الجنس\n2- تكون حاصله على اكتر من 80 نقاط نمو الدردشة\nلمعرفة النقاط نمو الدردشة : من خلال الصفحة الشخصية :ثم نمو الدردشة:و هتكون موضحه قدام حضرتك عدد النقاط"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nمرحبًا بك في مكانك!\n\nنعتذر عن المشكلة الحالية\n\nللحصول على رسائل التطابق\n1- اجتياز التحقق من الإطار والتحقق من الجنس\n2- تكون حاصله على اكتر من 80 نقاط نمو الدردشة\nلمعرفة النقاط نمو الدردشة : من خلال الصفحة الشخصية :ثم نمو الدردشة:و هتكون موضحه قدام حضرتك عدد النقاط\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-matching-issue-2", createSupportMacroContent("Matching Issue 2", [{"label": "Use Case", "text": "Arabic customer-support macro for: Matching Issue 2."}, {"label": "Answer", "text": "If all requirements are met and matching messages still do not appear, please note that the matching feature is system-based. When a suitable match is available, the system sends the message automatically. If no suitable match is available, no matching message will be sent."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nIf all requirements are met and matching messages still do not appear, please note that the matching feature is system-based. When a suitable match is available, the system sends the message automatically. If no suitable match is available, no matching message will be sent.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "مشكلة تطابق 2", [{"label": "الإجابة", "text": "بنعتذر عن المشكلة الحالية و لكن في حين توافر جميع الشروط و عدم تواجد تطابق\nيرجى العلم بأنها\nخاصيه التطابق خاصيه مساعده لو في تطابق مع الحساب السيستم بيبعتلك لو مفيش السيستم مبيبعتش حتى تقدرى تتواصلى مع الآخرين"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nمرحبًا بك في مكانك!\n\nبنعتذر عن المشكلة الحالية و لكن في حين توافر جميع الشروط و عدم تواجد تطابق\nيرجى العلم بأنها\nخاصيه التطابق خاصيه مساعده لو في تطابق مع الحساب السيستم بيبعتلك لو مفيش السيستم مبيبعتش حتى تقدرى تتواصلى مع الآخرين\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-matching-issue-3", createSupportMacroContent("Matching Issue 3", [{"label": "Use Case", "text": "Arabic customer-support macro for: Matching Issue 3."}, {"label": "Answer", "text": "This task appears at the beginning of account creation. After completing it, the other user must reply to you so you can receive the diamonds related to the task."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nThis task appears at the beginning of account creation. After completing it, the other user must reply to you so you can receive the diamonds related to the task.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "مشكلة تطابق 3", [{"label": "الإجابة", "text": "دى مهمه بتبقى في بدايه إنشاء الحساب و لما حضرتك بتخلصيها لازم الشخص الآخر يرد على حضرتك حتى تحصلى على ماسات"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nمرحبًا بك في مكانك!\n\nدى مهمه بتبقى في بدايه إنشاء الحساب و لما حضرتك بتخلصيها لازم الشخص الآخر يرد على حضرتك حتى تحصلى على ماسات\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-remove-game-request", createSupportMacroContent("Remove Game Request", [{"label": "Use Case", "text": "Arabic customer-support macro for: Remove Game Request."}, {"label": "Answer", "text": "The request to remove games has been sent to the relevant department, and the games will be removed from your account as soon as possible."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nThe request to remove games has been sent to the relevant department, and the games will be removed from your account as soon as possible.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طلب إزالة لعبة", [{"label": "الإجابة", "text": "تم إرسال طلب للقسم المختص لإزالة اللعبة وسيتم إزالتها لحضرتك في أقرب وقت ممكن يا فندم إن شاء الله."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nتم إرسال طلب للقسم المختص لإزالة اللعبة وسيتم إزالتها لحضرتك في أقرب وقت ممكن يا فندم إن شاء الله.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-remove-games-request", createSupportMacroContent("Remove Games Request", [{"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nWelcome! We are here to serve you.\n\nA request has been submitted to remove the games, and it will be resolved as soon as possible.\n\nWe appreciate your communication with us and look forward to serving you in the best possible way.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طلب إزالة الألعاب", [{"label": "الإجابة", "text": "تم تقديم طلب لإزالة الألعاب و سيتم حلها في أسرع وقت"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nتم تقديم طلب لإزالة الألعاب و سيتم حلها في أسرع وقت\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-app-crash-refresh-steps", createSupportMacroContent("App Crash / Refresh Steps", [{"label": "Use Case", "text": "Arabic customer-support macro for: App Crash / Refresh Steps."}, {"label": "Answer", "text": "Please refresh the app and upload the app log by following these steps:\n\n1- Go to Settings from the profile/code page.\n2- Select About Sugo.\n3- Tap Upload App Log and wait until the upload is complete.\n4- Close the app completely.\n5- Restart your phone.\n6- Log out of the app, then log in again.\n\nIf the issue continues after completing these steps, please send a video showing the message or issue that appears, and make sure your account ID is visible in the video."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nPlease refresh the app and upload the app log by following these steps:\n\n1- Go to Settings from the profile/code page.\n2- Select About Sugo.\n3- Tap Upload App Log and wait until the upload is complete.\n4- Close the app completely.\n5- Restart your phone.\n6- Log out of the app, then log in again.\n\nIf the issue continues after completing these steps, please send a video showing the message or issue that appears, and make sure your account ID is visible in the video.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "تعطل التطبيق وخطوات التنشيط", [{"label": "الإجابة", "text": "ممكن تقوم بعمل الخطوة التنشيطية و تتابع معنا مرة أخرى من خلال الخطوات التالية:\n1- الإعدادات\n2- ثم حول Sugo\n3- ثم الضغط على تحميل السجل وانتظار التحميل\n5- وإغلاق البرنامج وعمل restart للهاتف وعمل تسجيل خروج ودخول مرة أخرى للبرنامج.\nوإذا كنت تواجه نفس المشكلة قم بإرسال فيديو يوضح الرسالة التي تظهر لك، وأظهر رقم حسابك في الفيديو أيضًا."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nممكن تقوم بعمل الخطوة التنشيطية و تتابع معنا مرة أخرى من خلال الخطوات التالية:\n1- الإعدادات\n2- ثم حول Sugo\n3- ثم الضغط على تحميل السجل وانتظار التحميل\n5- وإغلاق البرنامج وعمل restart للهاتف وعمل تسجيل خروج ودخول مرة أخرى للبرنامج.\nوإذا كنت تواجه نفس المشكلة قم بإرسال فيديو يوضح الرسالة التي تظهر لك، وأظهر رقم حسابك في الفيديو أيضًا.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-app-crash-upload-log", createSupportMacroContent("App Crash / Upload Log", [{"label": "Use Case", "text": "Arabic customer-support macro for: App Crash / Upload Log."}, {"label": "Answer", "text": "Please refresh the app and upload the app log by following these steps:\n\n1- Go to Settings from the profile/code page.\n2- Select About Sugo.\n3- Tap Upload App Log and wait until the upload is complete.\n4- Close the app completely.\n5- Restart your phone.\n6- Log out of the app, then log in again.\n\nIf the issue continues after completing these steps, please send a video showing the message or issue that appears, and make sure your account ID is visible in the video."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nPlease refresh the app and upload the app log by following these steps:\n\n1- Go to Settings from the profile/code page.\n2- Select About Sugo.\n3- Tap Upload App Log and wait until the upload is complete.\n4- Close the app completely.\n5- Restart your phone.\n6- Log out of the app, then log in again.\n\nIf the issue continues after completing these steps, please send a video showing the message or issue that appears, and make sure your account ID is visible in the video.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "تعطل التطبيق ورفع السجل", [{"label": "الإجابة", "text": "ممكن تقوم بعمل الخطوة التنشيطية و تتابع معنا مرة أخرى من خلال الخطوات التالية: الإعدادات (في خانة الرمز الشخصي) ثم حول Sugo ثم الضغط على Upload App log وانتظار التحميل وإغلاق البرنامج وعمل restart للهاتف وعمل تسجيل خروج ودخول مرة أخرى للبرنامج. وإذا كنت تواجه نفس المشكلة قم بإرسال فيديو يوضح الرسالة التي تظهر لك، وأظهر رقم حسابك في الفيديو أيضًا."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nممكن تقوم بعمل الخطوة التنشيطية و تتابع معنا مرة أخرى من خلال الخطوات التالية: الإعدادات (في خانة الرمز الشخصي) ثم حول Sugo ثم الضغط على Upload App log وانتظار التحميل وإغلاق البرنامج وعمل restart للهاتف وعمل تسجيل خروج ودخول مرة أخرى للبرنامج. وإذا كنت تواجه نفس المشكلة قم بإرسال فيديو يوضح الرسالة التي تظهر لك، وأظهر رقم حسابك في الفيديو أيضًا.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-change-country", createSupportMacroContent("Change Country", [{"label": "Use Case", "text": "Arabic customer-support macro for: Change Country."}, {"label": "Answer", "text": "To change the country, please open the following link using Google Chrome and fill in all required information completely and correctly:\n\nhttps://micoworld.feishu.cn/share/base/form/shrcnKJhWoj7krB5Tt3Ydkobz6f?chunked=false\n\nAfter submitting the request, it will be processed within 24 to 48 hours."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo change the country, please open the following link using Google Chrome and fill in all required information completely and correctly:\n\nhttps://micoworld.feishu.cn/share/base/form/shrcnKJhWoj7krB5Tt3Ydkobz6f?chunked=false\n\nAfter submitting the request, it will be processed within 24 to 48 hours.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "تغيير البلد", [{"label": "الإجابة", "text": "إذا اردت تغيير البلد يرجى ملئ البيانات المطلوبه في الرابط بشكل كامل وصحيح لاتمام عمليه تغيير البلد ويتم العمل عليها خلال 24 ساعه من اتمام ارسال البيانات يرجى فتح الرابط على متصفح Google Chromehttps://micoworld.feishu.cn/share/base/form/shrcnKJhWoj7krB5Tt3Ydkobz6f?chunked=false"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nتم إرسال طلب للقسم المختص بإضافة اللعبة وسيتم إضافتها لحضرتك في أقرب وقت ممكن يا فندم إن شاء الله.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-change-country-follow-up", createSupportMacroContent("Change Country Follow-Up", [{"label": "Use Case", "text": "Arabic customer-support macro for: Change Country Follow-Up."}, {"label": "Answer", "text": "To change the country, please open the following link using Google Chrome and fill in all required information completely and correctly:\n\nhttps://micoworld.feishu.cn/share/base/form/shrcnKJhWoj7krB5Tt3Ydkobz6f?chunked=false\n\nAfter submitting the request, it will be processed within 24 to 48 hours."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo change the country, please open the following link using Google Chrome and fill in all required information completely and correctly:\n\nhttps://micoworld.feishu.cn/share/base/form/shrcnKJhWoj7krB5Tt3Ydkobz6f?chunked=false\n\nAfter submitting the request, it will be processed within 24 to 48 hours.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "متابعة تغيير البلد", [{"label": "الإجابة", "text": "بخصوص تغيير البلد\n1- يرجى فتح اللينك على Google Chrome\n2- يرجى ملئ البيانات كامله بشكل صحيح\nبعد إرسال الطلب يتم العمل عليه في خلال 24 ساعه ل 48 ساعه\nhttps://micoworld.feishu.cn/share/base/form/shrcnKJhWoj7krB5Tt3Ydkobz6f?chunked=false"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nبخصوص تغيير البلد\n1- يرجى فتح اللينك على Google Chrome\n2- يرجى ملئ البيانات كامله بشكل صحيح\nبعد إرسال الطلب يتم العمل عليه في خلال 24 ساعه ل 48 ساعه\nhttps://micoworld.feishu.cn/share/base/form/shrcnKJhWoj7krB5Tt3Ydkobz6f?chunked=false\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-close-location-hide-distance", createSupportMacroContent("Close Location / Hide Distance", [{"label": "Use Case", "text": "Arabic customer-support macro for: Close Location / Hide Distance."}, {"label": "Answer", "text": "To fully stop distance visibility, please disable the location permission from your phone settings. Go to phone Settings, then Apps, then Sugo, then Permissions, and turn off Location permission."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo fully stop distance visibility, please disable the location permission from your phone settings. Go to phone Settings, then Apps, then Sugo, then Permissions, and turn off Location permission.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "إغلاق الموقع أو إخفاء المسافة", [{"label": "الإجابة", "text": "لو عاوز تقفل المسافة نهائي بتقفل اللوكيشن نفسه من الموبايل و لو متقفلش بتخش على الإعدادات بتاعت الموبايل وبعد كدا Apps وبعد كدا Sugo وبعدين permissions وبتقفل اللوكيشن"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nمرحبًا بك في مكانك!\n\nلو عاوز تقفل المسافة نهائي بتقفل اللوكيشن نفسه من الموبايل\nو لو متقفلش بتخش على الإعدادات بتاعت الموبايل وبعد كدا Apps\nثم Sugo\nثم permissions وبتقفل اللوكيشن\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-refined-location-disappeared", createSupportMacroContent("Location Disappeared", [{"label": "Use Case", "text": "Arabic customer-support macro for: Location Disappeared."}, {"label": "Answer", "text": "To stop nearby people from appearing, please go to the Me page, then Settings, then Privacy, and turn off the Nearby People visibility option."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo stop nearby people from appearing, please go to the Me page, then Settings, then Privacy, and turn off the Nearby People visibility option.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "اختفاء الموقع", [{"label": "الإجابة", "text": "نتطلع لتلبية احتياجاتك. الدخول على صفحة أنا ثم الإعدادات ثم الخصوصية يوجد بها ظهور توقف ظهور الأشخاص المقربين اضغط عليها لقفلها"}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nالدخول على صفحة أنا ثم الإعدادات ثم الخصوصية يوجد بها ظهور توقف ظهور الأشخاص المقربين اضغط عليها لقفلها\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));


